  ["tips.units.members"] = "Filter |cffffffffGuild|r PlayerBots\n|cffffffffShows the Guild Roster.\nDoes not show your characters, even if they're in the guild.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.friends"] = "Filter |cffffffffFriends Listk|r PlayerBots\n|cffffffffShows the Friend Roster.\nDoes not show your characters or the Guild roster, even if they're in those rosters.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.favorites"] = "Roster Filter\n|cffffffffShow only the Bots you marked as Favorites.|r\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: System)|r",
  ["tips.units.pvpstatsmaster"] = "PvP Stats\n|cffffffffSend PvP Stats command to...|r\n\n|cffff0000Left-click to open menu|r\n|cff999999(Executed by: System)|r",
  ["tips.units.pvpstatstobot"] = "Send To Bot",
  ["tips.units.pvpstatstoparty"] = "Send To Party",
  ["tips.units.pvpstatstoraid"] = "Send To Raid",
  ["tips.units.browse"] = "Browse\n|cffffffffBrowse through your PlayerBot rosters.\nHidden when there are less than 11 PlayerBots in total.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.invite"] = "Invite Main Menu\n|cffffffffAutomatically fills your Group with PlayerBots.\nLeft side button is 'Party Invite'. Right side buttons are 'Raid Invite'.\nRight-clicking this button will remove all PlayerBots at once.\nThis means that if you are not in any Group, this function will add or remove PlayerBots as necessary.|r\n\n|cffff0000Left-click to show or hide the menu|r\n|cff999999(Executed by: System)|r\n\n|cffff0000Right-click to add or remove all Bots|r\n|cff999999(Executed by: System)|r",
  ["tips.units.inviteParty5"] = "5-Man Party\n|cffffffffFills your Party with up to 5 PlayerBots.\nPlayerBots are added from the selected Roster, ignoring any Class filters.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.inviteRaid10"] = "10-Man Raid Group\n|cffffffffFills your Raid Group with up to 10 PlayerBots.\nPlayerBots are added from the selected Roster, ignoring any Class filters.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.inviteRaid25"] = "25-Man Raid Group\n|cffffffffFills your Raid Group with up to 25 PlayerBots.\nPlayerBots are added from the selected Roster, ignoring any Class filters.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.inviteRaid40"] = "40-Man Raid Group\n|cffffffffFills your Raid Group with up to 40 PlayerBots.\nPlayerBots are added from the selected Roster, ignoring any Class filters.|r\n\n|cffff0000Left-click to activate.|r\n|cff999999(Executed by: System)|r",
  ["tips.units.alliance"] = "Log In/Out All PlayerBots\n|cffffffffLog in/Out all PlayerBots you have access to.\nThis function will take time to populate the ButtonBars for each PlayerBot, depending on the number of PlayerBots total.\n\n|cffff0000Left-click to log in all PlayerBots|r\n|cff999999(Executed by: System)|r\n\n|cffff0000Right-click to log out all PlayerBots|r\n|cff999999(Executed by: System)|r",
