  ["tips.main.master"] = "AddOn Configuration Menu\n|cffffffffConfigures AddOn appearance and button layout.\n|cffff0000Left-click to show or hide the Options|r\n|cff999999(Executed by: System)|r\n\n|cffff0000Right-click to drag and move MultiBot windows|r\n|cff999999(Executed by: System)|r",
  ["tips.main.options"] = "Options Panel\n|cffffffffOpens the MultiBot settings panel with sliders for action intervals.\n(Stats / Talents / Invite / Sort) and chat throttling (Messages per second / Burst).\nSettings are saved per character.|r\n\n|cffff0000Left-Click to open or close the options panel|r\n|cff999999(Executed by: Interface)|r",
  ["tips.main.coords"] = "Reset Window Locations\n|cffffffffReset the screen locations of the following to their default values:\nMultiBar, Inventory, Spellbook, Itemus, Iconos and Reward-Selector|r\n\n|cffff0000Left-click to reset to default|r\n|cff999999(Executed by: System)|r",
  ["tips.main.masters"] = "GameMaster Button Toggle\n|cffffffffEnables or disables the GameMaster Button on the AddOn toolbar.\nThis function requires Game Master account level access.|r\n\n|cffff0000Left-click to toggle the GameMaster-Control|r\n|cff999999(Executed by: System)|r",
  ["tips.main.rtsc"] = "RTSC Toggle\n|cffffffffEnables or disables RTSC control.|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r",
  ["tips.main.raidus"] = "Raidus Window\n|cffffffffOpens or closes the Raidus Raid Manager.|r\n\n|cffff0000Left-click to open or close|r\n|cff999999(Executed by: System)|r",
  ["tips.main.creator"] = "Creator Control Toggle \n|cffffffffEnables or disables the Creator control.|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r",
  ["tips.main.beast"] = "NPC-Beastmaster Main Menu\n|cffffffffEnables or disable the NPC-Beastmaster controls.\nThe NPC-Beastmaster module for Azerothcore allows every Character to have a Hunter Pet and give it Pet Commands.\nCharacters learn the necessary spells from the White Fang NPC, placed into the World by the GameMaster.|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r",
  ["tips.main.expand"] = "Expand Stay/Follow Menu\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: System)|r",
  ["tips.main.release"] = "Auto-Release\n|cffffffffDead Bots are automatically released and summoned.\nBots are revived immediately.|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r",
  ["tips.main.stats"] = "Auto-Stats\n|cffffffffDisplays Stats values, updated every 45 Seconds.|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r",
  ["tips.main.reward"] = "Reward Selection\n|cffffffffShows the Reward Selection window.\nIt is suggested to select the reward for your character first.\nThis prevents issues with using the Inspect buttons.|r\n\n|cffff00ffCAUTION:\nBots must also complete the same quest as you.\nDo not close the Reward Selection window after your character receives their quest reward.|r\n\n|cffffffffConfiguration for 'playerbots.conf':\n- (required) AiPlayerbot.AutoPickReward = no\n- (recommended) AiPlayerbot.SyncQuestWithPlayer = 1|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r\n\n|cffff0000Right-click to open|r\n|cff999999(Executed by: System)|r",
  ["tips.main.reset"] = "Reset Bot AI\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Target, Raid, Party)|r",
  ["tips.main.action"] = "Reset Action\n|cffffffffResets the current action of your Bots.|r\n\n|cffff0000Left-click to reset the action|r\n|cff999999(Executed by: Target, Raid, Party)|r",
  ["tips.game.master"] = "GameMaster Main Menu\n|cffffffffUseful GameMaster functions and utilities.\n|cffff00ffRequires GameMaster rights.|r\n\n|cffff0000Left-click to show or hide the Options|r\n|cff999999(Executed by: System)|r\n\n|cffff0000Right-click to close MultiBot|r\n|cff999999(Executed by: System)|r",
  ["tips.game.necronet"] = "Necro-Network\n|cffffffffEnables or disables Necro-Network.\nIf Necro-Network is active you will find Graveyard buttons on the World Map.\nWith each Graveyard button you could teleport yourself to the corresponding Graveyard.\nRequires GameMaster rights.|r\n\n|cffff0000Left-click to toggle|r\n|cff999999(Executed by: System)|r",
  ["tips.game.portal"] = "Memory Portal\n|cffffffffContains Memory Gems.\nUse the Memory Gems to store your current Location.\nYou can teleport yourself to any stored Locations by using the Memory Gems.\n|cffff0000Left-click to show or hide the Memory Gems|r\n|cff999999(Executed by: System)|r",
  ["tips.game.memory"] = "Memory-Gem\n|cffffffffThis Memory-Gem ABOUT.\nYou need GameMaster-Rights to use this Button.|r\n\n|cffff0000Left-click to store or teleport to the Location|r\n|cff999999(Executed by: Yourself)|r\n\n|cffff0000Right-click to forget the Location|r\n|cff999999(Executed by: Yourself)|r",
  ["tips.game.itemus"] = "Itemus\n|cffffffffContains every item in the game to give to anyone.\nTarget the Player or Bot, left-click the Item and it is generated for them.\nCaution: not every Item can be generated; requires experimentation.\n|cffff0000Left-click to open or close the Itemus|r\n|cff999999(Executed by: System)|r",
  ["tips.game.iconos"] = "Iconos\n|cffffffffShows every Icon and its file Path.\n|cffff0000Left-click to open or close the Iconos|r\n|cff999999(Executed by: System)|r",
  ["tips.game.summon"] = "Summon\n|cffffffffSummons a targeted Player or Bot to your position.\nRequires GameMaster rights.|r\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Target)|r",
  ["tips.game.appear"] = "Teleport to Player\n|cffffffffTeleports you the position of the targeted Player or Bot.\nRequires GameMaster rights.|r\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Target)|r",
  ["tips.game.delsvwarning"] = "|cffff4444WARNING|r : you are about to delete ALL MultiBot saved data.\nThis action cannot be undone.\n\nAre you sure?",
  ["tips.game.delsv"] = "Delete Saved Variables\n|cffffffffThis action will permanently erase all data from the MultiBot SavedVariables file (MultiBot.lua).\nThis action cannot be undone. Are you sure?|r\n\n|cffff0000Left-click to confirm|r\n|cff999999(Executed at system level)|r",
  ["tips.quests.master"] = "Quest Log\n|cffffffffShows the current Quest Log.\nLeft-click pages to share the quest with your Bots.\nRight-click pages to abandon your and your Bots' quest.\n|cffff0000Left-click to show or hide the Options|r\n|cff999999(Executed by: System)|r\n\n|cffff0000Right-click to refresh the Options|r\n|cff999999(Executed by: System)|r",
  ["tips.quests.accept"] = "Accept Quest\n|cffffffffOrders Bots to take every quest given by the targeted NPC.\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Raid, Party)|r",
  ["tips.quests.main"] = "Open Quests Menu\n|cffffffff|cffff0000Left-click to open|r\n|cff999999(Executed by: System)|r",
  ["tips.quests.talk"] = "Talk to NPC\n|cffffffffOrders Bots to talk to the selected NPC to accept or turn in a Quest.\n\n|cffff0000Left-click to order|r\n|cff999999(Executed by: Raid, Party)|r",
  ["tips.quests.talkerror"] = "Please select an NPC to talk to.",
  ["tips.quests.questcomperror"] = "Please select a Bot in order to view their quests.",
  ["tips.quests.sendwhisp"] = "Whisper to the Bot",
  ["tips.quests.sendpartyraid"] = "Group or Raid chat",
  ["tips.quests.completed"] = "Completed Quests\n|cffffffffShows a list of completed Quests by Bots.\n\n|cffff0000Left-click to open submenu|r\n|cff999999(Executed by: Raid, Party, Bot)|r",
  ["tips.quests.incompleted"] = "Incomplete Quests\n|cffffffffShows a list of incomplete Quests for Bots.\n\n|cffff0000Left-click to open submenu|r\n|cff999999(Executed by: Raid, Party, Bot)|r",
  ["tips.quests.allcompleted"] = "All Quests\n|cffffffffShows a list of all Quests for Bots.\n\n|cffff0000Left-click to open submenu|r\n|cff999999(Executed by: Raid, Party, Bot)|r",
  ["tips.quests.incomplist"] = "Current Quests from Bot(s)",
