  ["tips.quests.incompheader"] = "** Incomplete Quests **",
  ["tips.quests.botsword"] = "Bots : ",
  ["tips.quests.gobsmaster"] = "Game Objects Menu\n|cffffffffOpens the Use Game Objects Menu.|r\n\n|cffff0000Left-click to Open|r\n|cff999999(Executed by: System)|r",
  ["tips.quests.gobenter"] = "Use Game Object\n|cffffffffOpens a prompt to enter Game Object Name.\n\n|cffff0000Left-click to open prompt|r\n|cff999999(Executed by: Bot)|r",
  ["tips.quests.gobsearch"] = "Search for Game Object\n|cffffffffOpens a dialog box that shows Game Objects that Bots can use.\n\n|cffff0000Left-click to open frame|r\n|cff999999(Executed by: System)|r",
  ["tips.quests.goberrorname"] = "Please enter a valid Game Object Name.",
  ["tips.quests.gobselectboterror"] = "Please select the Bot to send the command to.",
  ["tips.quests.gobsnameerror"] = "Please enter a name.",
  ["tips.quests.gobctrlctocopy"] = "CTRL + C To Copy",
