  ["tips.quests.gobsfound"] = "Game Objects Found",
  ["tips.quests.gobpromptname"] = "Game Object Name",
  ["tips.quests.gobnosearchdata"] = "No search data captured.",
  ["tips.group.group"] = "Group Actions Selector\n|cffffffffThis opens a submenu with the following group actions:\nDrink, Release, Revive.|r\n\n|cffff0000Left-click to expand.|r",
  ["tips.drink.group"] = "Group Drink\n|cffffffffOrders the Group to drink/eat.\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Raid, Party)|r",
  ["tips.release.group"] = "Group Release\n|cffffffffReleases the spirits of all dead Bots to the nearest Graveyard.\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Raid, Party)|r",
  ["tips.revive.group"] = "Group Revive\n|cffffffffRevives dead Bots at the nearest Graveyard.\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Raid, Party)|r",
  ["tips.summon.group"] = "Group Summon\n|cffffffffSummons entire Party or Raid to your location.\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Raid, Party)|r",
  ["tips.allbots.sellallvendor"] = "Sell all vendorable Grey items (ALL BOTS)|cffffffff\nAll your bots (those listed in the Units panel) will sell all items\nthat can safely be sold to your current vendor target.\nProtected items (keys, Hearthstone, etc.) are never sold.|r\n\n|cffff0000Affects every bot listed in the Units panel.|r\n|cff999999(Executed by: each Bot)|r",
  ["tips.allbots.commandsallbots"] = "Allows you to send commands to all Bots|cffffffff\nAll your bots (those listed in the Units panel) will execute the command\n\n|cffff0000Affects every bot listed in the Units panel.|r\n|cff999999(Executed by: each Bot)|r",
  ["tips.allbots.maintenanceallbots"] = "Maintenance (ALL BOTS)|cffffffff\nAll your bots (those listed in the Units panel) will run the 'maintenance' command.\nUse this when you want every bot to perform its full maintenance routine at once.|r\n\n|cffff0000Affects every bot listed in the Units panel.|r\n|cff999999(Executed by: each Bot)|r",
  ["tips.inventory.sell"] = "Sell Items|cffffffff\nInventory Sell Mode.\nTarget an NPC vendor to use this mode.\nFor security reasons, Bots will not sell:\n- any item with 'Key' in its name\n- the Hearthstone|r\n\n|cffff0000Left-click an item to sell\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.sellgrey"] = "Sell * (grey items)|cffffffff\nThe Bot sells all poor-quality (grey) items to the selected vendor.\nMake sure you have the vendor selected and that the Bot is in range.|r\n\n|cffff0000Only affects the Bot whose inventory is open.|r\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.sellvendor"] = "Sell vendorable items|cffffffff\nThe Bot sells all items that can safely be sold to the selected vendor.\nProtected items (keys, Hearthstone, etc.) are never sold.|r\n\n|cffff0000Only affects the Bot whose inventory is open.|r\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.equip"] = "Equip Items|cffffffff\nBots equip items in their inventory.|r\n\n|cffff0000Left-click an item for the Bot to equip|r\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.use"] = "Use Items|cffffffff\nBots use consumable items in their inventory.|r\n\n|cffff0000Left-click an item for the Bot to use|r\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.trade"] = "Trade Items|cffffffff\nTrade with Bots items from their inventory.\nThe Inspect window must be closed manually.|r\n\n|cffff0000Left-click an item for the Bot to trade|r\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.drop"] = "Drop Items|cffffffff\nChoose items in the Bots' inventory to drop.\nFor security reasons, Bots will not drop:\n- any Epic or higher rarity item\n- any item with 'Key' in its name\n- the Hearthstone|r\n\n|cffff0000Left-click an item for the Bot to drop|r\n|cff999999(Executed by: Bot)|r",
  ["tips.inventory.open"] = "Open Items|cffffffff\nBots open any loot bag item in their inventory.\nThe contents automatically go into their inventory.\n|cffff0000Left-click a loot bag item for the Bot to open|r\n|cff999999(Executed by: Bot)|r",
  ["tips.itemus.level.master"] = "Level Filter|cffffffff\nFilters the Items by Level in intervals of 10.|r\n\n|cffff0000Left-click to show or hide Options|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L10"] = "iLevel 1-10|cffffffff\nShows 1-10 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L20"] = "iLevel 11-20|cffffffff\nShows 11-20 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L30"] = "iLevel 21-30|cffffffff\nShows 21-30 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L40"] = "iLevel 31-40|cffffffff\nShows 31-40 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L50"] = "iLevel 41-50|cffffffff\nShows 41-50 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L60"] = "iLevel 51-60|cffffffff\nShows 51-60 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L70"] = "iLevel 61-70|cffffffff\nShows 61-70 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.level.L80"] = "iLevel 71-80|cffffffff\nShows 71-80 iLevel items|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.master"] = "Rarity Filter|cffffffff\nFilters items by Rarity.\nCombines with the iLevel filter.|r\n\n|cffff0000Left-click to show or hide Options|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.R00"] = "Junk|cffffffff\nShows|r |cff808080Junk|r |cffffffffRarity items.|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.R01"] = "Common|cffffffff\nShows Common (White) Rarity items.|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.R02"] = "Uncommon|cffffffff\nShows|r |cff1eff00Uncommon|r |cffffffffRarity items.|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.R03"] = "Rare|cffffffff\nShows|r |cff0070ddRare|r |cffffffffRarity items.|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.R04"] = "Epic|cffffffff\nShows|r |cffa335eeEpic|r |cffffffffRarity items.|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
  ["tips.itemus.rare.R05"] = "Legendary|cffffffff\nShows|r |cffff8000Legendary|r |cffffffffRarity items.|r\n\n|cffff0000Left-click to set|r\n|cff999999(Executed by: System)|r",
