  ["tips.deathknight.presence.frost"] = "Frost|cffffffff\nActivates Frost Specialisation.|r\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Bot)|r",
  ["tips.deathknight.presence.blood"] = "BLood|cffffffff\nActivates Blood Specialisation.|r\n\n|cffff0000Left-click to activate|r\n|cff999999(Executed by: Bot)|r",
  ["tips.deathknight.dps.master"] = "DPS Control|cffffffff\nControls Death Knight DPS strategy.|r\n\n|cffff0000Left-click to show or hide|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.deathknight.dps.dpsAssist"] = "DPS Assist|cffffffff\nActivates DPS Assist strategy.\nDPS AoE, DPS Assist and Tank Assist are mutually exclusive.\nOnly one DPS strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.deathknight.dps.dpsAoe"] = "DPS AoE|cffffffff\nActivates DPS AoE strategy, focusing on area-of-effect (AoE) abilities to hit multiple enemies.\nDPS AoE, DPS Assist and Tank Assist are mutually exclusive.\nOnly one DPS strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.deathknight.dps.frostAoe"] = "FROST-AOE|cffffffff\nEnables the Frost AOE strategy.\nFrost-AOE, DPS-Assist and Tank-Assist are mutually exclusive.\nOnly one of these strategies can be active.|r\n\n|cffff0000Left-Click to enable or disable Frost-AOE|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.deathknight.dps.unholyAoe"] = "UNHOLY-AOE|cffffffff\nEnables the Unholy AOE strategy.\nUnholy-AOE, DPS-Assist and Tank-Assist are mutually exclusive.\nOnly one of these strategies can be active.|r\n\n|cffff0000Left-Click to enable or disable Unholy-AOE|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.deathknight.tankAssist"] = "Tank Assist|cffffffff\nActivates Tank Assist strategy.\nDPS AoE, DPS Assist and Tank Assist are mutually exclusive.\nOnly one DPS strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.heal"] = "Heal|cffffffff\nAssigns the Druid as the Group's Healer.\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.buff"] = "Buff|cffffffff\nAssigns the Druid to apply buffs to the Group.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.master"] = "Druid Class Roles|cffffffff\nContains typical Druid class roles.|r\n\n|cffff0000Left-click to show or hide Class Roles|r\n|cf9999999(Executed by: System)|r",
  ["tips.druid.playbook.casterDebuff"] = "Debuff|cffffffff\nThe Druid casts debuff spells during combat.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.casterAoe"] = "AoE|cffffffff\nThe Druid casts AoE spells during combat.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.caster"] = "DPS Ranged|cffffffff\nThe Druid casts ranged attack spells during combat.|r\n\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.catAoe"] = "Cat AoE|cffffffff\nAs a Cat, the Druid uses AoE attacks during combat.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.cat"] = "Cat Form|cffffffff\nAs a Cat, the Druid assumes the role of Melee attacker.|r\n\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.bear"] = "Bear Form|cffffffff\nAs a Bear, the Druid assumes the role of Tank.|r\n\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.playbook.melee"] = "Melee|cffffffff\nEnable the Melee strategy.\nStays in melee range, preferring physical attacks.\nMutually exclusive with Caster and Heal.|r\n\n|cffff0000Left-Click to enable or disable Melee|r\n|cff999999(Executed by: Bot)|r",
  ["tips.druid.dps.healerdps"] = "Healer DPS|cffffffff\nEnable the hybrid Healer-DPS strategy.\nDeals damage by default, healing when needed.\nMutually exclusive with Heal and OffHeal.|r\n\n|cffff0000Left-Click to enable or disable Healer-DPS|r\n|cff999999(Executed by: Bot)|r",
  ["tips.druid.dps.master"] = "Druid DPS Control|cffffffff\nDruid DPS strategies|r\n\n|cffff0000Left-click to show or hide DPS-Control|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.dps.dpsAssist"] = "DPS Assist|cffffffff\nActivates DPS Assist strategies.\nDPS AoE, DPS Assist and Tank Assist are mutually exclusive.\nOnly one DPS strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.dps.dpsDebuff"] = "DPS Debuff|cffffffff\nAs an Offensive Spellcaster, the Druid activates Debuff strategies.\nOnly one DPS strategy may be active at a time.|r\n\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.dps.dpsAoe"] = "DPS AoE|cffffffff\nAs a Cat or Offensive Spellcaster, the Druid casts area-of-effect spells to deal damage to multiple enemies.\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nDPS AoE, DPS Assist and Tank Assist are mutually exclusive.\nOnly one DPS strategy or Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.dps.dps"] = "DPS|cffffffff\nDPS AoE|cffffffff\nAs a Cat, the Druid assumes the role of Melee attacker.\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one DPS strategy or Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.dps.offheal"] = "Off-Heal|cffffffff\nSwitches from DPS to Off-Heal.\nAs a Feral Druid, they focus on dealing damage, healing group members as needed.\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.tankAssist"] = "Tank Assist|cffffffff\nActivates Tank Assist strategies.\nDPS AoE, DPS Assist, and Tank Assist are mutually exclusive.\nOnly one may be active at a time at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
  ["tips.druid.tank"] = "Tank|cffffffff\nAs a Bear, the Druid assumes the role of Tank.\nBear, Cat, Offensive Spellcaster, and Healer are mutually exclusive.\nOnly one Druid strategy may be active at a time.|r\n\n|cffff0000Left-click to toggle|r\n|cf9999999(Executed by: Bot)|r",
